   119→func (l *base) runningKernel() (release, version string, err error) {
   120→	r := l.exec("uname -r", noSudo)
   121→	if !r.isSuccess() {
   122→		return "", "", xerrors.Errorf("Failed to SSH: %s", r)
   123→	}
   124→	release = strings.TrimSpace(r.Stdout)
   125→
   126→	switch l.Distro.Family {
   127→	case constant.Debian:
   128→		r := l.exec("uname -a", noSudo)
   129→		if !r.isSuccess() {
   130→			return "", "", xerrors.Errorf("Failed to SSH: %s", r)
   131→		}
   132→		ss := strings.Fields(r.Stdout)
   133→		if 6 < len(ss) {
   134→			version = ss[6]
   135→		}
   136→		if _, err := debver.NewVersion(version); err != nil {
   137→			l.log.Warnf("kernel running version is invalid. skip kernel vulnerability detection. actual kernel version: %s, err: %s", version, err)
   138→			version = ""
   139→		}
   140→	}
   141→	return
   142→}
