   249→func (l *base) parseDockerPs(stdout string) (containers []config.Container, err error) {
   250→	lines := strings.Split(stdout, "\n")
   251→	for _, line := range lines {
   252→		fields := strings.Fields(line)
   253→		if len(fields) == 0 {
   254→			break
   255→		}
   256→		if len(fields) != 3 {
   257→			return containers, xerrors.Errorf("Unknown format: %s", line)
   258→		}
   259→		containers = append(containers, config.Container{
   260→			ContainerID: fields[0],
   261→			Name:        fields[1],
   262→			Image:       fields[2],
   263→		})
   264→	}
   265→	return
   266→}
   267→
   268→func (l *base) parseLxdPs(stdout string) (containers []config.Container, err error) {
   269→	lines := strings.Split(stdout, "\n")
   270→	for i, line := range lines[3:] {
   271→		if i%2 == 1 {
   272→			continue
   273→		}
   274→		fields := strings.Fields(strings.Replace(line, "|", " ", -1))
   275→		if len(fields) == 0 {
   276→			break
   277→		}
   278→		if len(fields) != 1 {
   279→			return containers, xerrors.Errorf("Unknown format: %s", line)
   280→		}
   281→		containers = append(containers, config.Container{
   282→			ContainerID: fields[0],
   283→			Name:        fields[0],
   284→		})
   285→	}
   286→	return
   287→}
   288→
   289→func (l *base) parseLxcPs(stdout string) (containers []config.Container, err error) {
   290→	lines := strings.Split(stdout, "\n")
