   365→var dsFingerPrintPrefix = "AgentStatus.agentCertHash: "
   366→
   367→func (l *base) detectDeepSecurity() (string, error) {
   368→	// only work root user
   369→	if l.getServerInfo().Mode.IsFastRoot() {
   370→		if r := l.exec("test -f /opt/ds_agent/dsa_query", sudo); r.isSuccess() {
   371→			cmd := fmt.Sprintf(`/opt/ds_agent/dsa_query -c "GetAgentStatus" | grep %q`, dsFingerPrintPrefix)
   372→			r := l.exec(cmd, sudo)
   373→			if r.isSuccess() {
   374→				line := strings.TrimSpace(r.Stdout)
   375→				return line[len(dsFingerPrintPrefix):], nil
   376→			}
   377→			l.warns = append(l.warns, xerrors.New("Fail to retrieve deepsecurity fingerprint"))
   378→		}
   379→	}
   380→	return "", xerrors.Errorf("Failed to detect deepsecurity %s", l.ServerInfo.ServerName)
   381→}
