   901→func (l *base) execPortsScan(scanDestIPPorts map[string][]string) ([]string, error) {
   902→	if l.getServerInfo().PortScan.IsUseExternalScanner {
   903→		listenIPPorts, err := l.execExternalPortScan(scanDestIPPorts)
   904→		if err != nil {
   905→			return []string{}, err
   906→		}
   907→		return listenIPPorts, nil
   908→	}
   909→
   910→	listenIPPorts, err := l.execNativePortScan(scanDestIPPorts)
   911→	if err != nil {
   912→		return []string{}, err
   913→	}
   914→
   915→	return listenIPPorts, nil
   916→}
