   918→func (l *base) execNativePortScan(scanDestIPPorts map[string][]string) ([]string, error) {
   919→	l.log.Info("Using Port Scanner: Vuls built-in Scanner")
   920→
   921→	listenIPPorts := []string{}
   922→
   923→	for ip, ports := range scanDestIPPorts {
   924→		if !isLocalExec(l.ServerInfo.Port, l.ServerInfo.Host) && net.ParseIP(ip).IsLoopback() {
   925→			continue
   926→		}
   927→
   928→		for _, port := range ports {
   929→			scanDest := ip + ":" + port
   930→			isOpen, err := nativeScanPort(scanDest)
   931→			if err != nil {
   932→				return []string{}, err
   933→			}
   934→
   935→			if isOpen {
   936→				listenIPPorts = append(listenIPPorts, scanDest)
   937→			}
   938→		}
   939→	}
   940→
   941→	return listenIPPorts, nil
   942→}
   943→
   944→func nativeScanPort(scanDest string) (bool, error) {
   945→	conn, err := net.DialTimeout("tcp", scanDest, time.Duration(1)*time.Second)
   946→	if err != nil {
   947→		if strings.Contains(err.Error(), "i/o timeout") || strings.Contains(err.Error(), "connection refused") {
   948→			return false, nil
   949→		}
   950→		if strings.Contains(err.Error(), "too many open files") {
   951→			time.Sleep(time.Duration(1) * time.Second)
   952→			return nativeScanPort(scanDest)
   953→		}
   954→		return false, err
   955→	}
   956→	conn.Close()
   957→
   958→	return true, nil
   959→}
