    87→// NeedsUpdate check is DB needs update
    88→func (c *Client) NeedsUpdate(cliVersion string, skip bool) (bool, error) {
    89→	meta, err := c.metadata.Get()
    90→	if err != nil {
    91→		log.Logger.Debugf("There is no valid metadata file: %s", err)
    92→		if skip {
    93→			log.Logger.Error("The first run cannot skip downloading DB")
    94→			return false, xerrors.New("--skip-update cannot be specified on the first run")
    95→		}
    96→		meta = metadata.Metadata{Version: db.SchemaVersion}
    97→	}
    98→
    99→	if db.SchemaVersion < meta.Version {
   100→		log.Logger.Errorf("Trivy version (%s) is old. Update to the latest version.", cliVersion)
   101→		return false, xerrors.Errorf("the version of DB schema doesn't match. Local DB: %d, Expected: %d",
   102→			meta.Version, db.SchemaVersion)
   103→	}
   104→
   105→	if skip {
   106→		log.Logger.Debug("Skipping DB update...")
   107→		if err = c.validate(meta); err != nil {
   108→			return false, xerrors.Errorf("validate error: %w", err)
   109→		}
   110→		return false, nil
   111→	}
   112→
   113→	if db.SchemaVersion != meta.Version {
   114→		log.Logger.Debugf("The local DB schema version (%d) does not match with supported version schema (%d).", meta.Version, db.SchemaVersion)
   115→		return true, nil
   116→	}
   117→
   118→	return !c.isNewDB(meta), nil
   119→}
