   130→func (c *Client) isNewDB(meta metadata.Metadata) bool {
   131→	if c.clock.Now().Before(meta.NextUpdate) {
   132→		log.Logger.Debug("DB update was skipped because the local DB is the latest")
   133→		return true
   134→	}
   135→
   136→	if c.clock.Now().Before(meta.DownloadedAt.Add(time.Hour)) {
   137→		log.Logger.Debug("DB update was skipped because the local DB was downloaded during the last hour")
   138→		return true
