// testPNPMEcosystemDetection validates that PNPM lockfiles are properly recognized
func testPNPMEcosystemDetection(t *testing.T) {
	// PNPM uses pnpm-lock.yaml as its lockfile
	pnpmLockfile := "pnpm-lock.yaml"

	// Check if PNPM lockfile is in the LibraryMap
	ecosystemType, exists := models.LibraryMap[pnpmLockfile]
	if !exists {
		t.Errorf("REGRESSION: PNPM lockfile '%s' not found in LibraryMap. PNPM projects will not be scanned for vulnerabilities.", pnpmLockfile)
	}

	// Check if library type is correctly mapped to "node" ecosystem
	if exists && ecosystemType != "node" {
		t.Errorf("REGRESSION: PNPM lockfile should map to 'node' ecosystem, got '%s'", ecosystemType)
	}

	// Verify that PNPM packages can be processed
	libScanner := models.LibraryScanner{
		Type:         "pnpm",
		LockfilePath: "/app/pnpm-lock.yaml",
		Libs: []models.Library{
			{Name: "lodash", Version: "4.17.20"},
		},
	}

	// This should not panic - PNPM type should be recognized
	key := libScanner.GetLibraryKey()
	if !exists && key == "" {
		t.Errorf("REGRESSION: PNPM scanner returned empty library key due to missing ecosystem support")
	}
	if exists && key != "node" {
		t.Errorf("REGRESSION: PNPM scanner should return library key 'node', got '%s'", key)
	}
}

// testDotNetEcosystemDetection validates that .NET lockfiles are properly recognized
func testDotNetEcosystemDetection(t *testing.T) {
	testCases := []struct {
		name     string
		filename string
		expected string
	}{
		{
			name:     "NuGet packages lock",
			filename: ftypes.NuGetPkgsLock,
			expected: ".net",
		},
		{
			name:     "NuGet packages config",
			filename: ftypes.NuGetPkgsConfig,
			expected: ".net",
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			if _, exists := models.LibraryMap[tc.filename]; !exists {
				t.Errorf(".NET lockfile '%s' not found in LibraryMap", tc.filename)
			}

			if models.LibraryMap[tc.filename] != tc.expected {
				t.Errorf("Expected '%s' for %s, got '%s'", tc.expected, tc.filename, models.LibraryMap[tc.filename])
			}
		})
	}

	// Verify NuGet type is recognized
	libScanner := models.LibraryScanner{
		Type:         ftypes.NuGet,
		LockfilePath: "/app/packages.lock.json",
		Libs: []models.Library{
			{Name: "Newtonsoft.Json", Version: "13.0.1"},
		},
	}

	key := libScanner.GetLibraryKey()
	if key != ".net" {
		t.Errorf("NuGet scanner should return library key '.net', got '%s'", key)
	}
}

// testAnalyzerScopeControl validates that non-library analyzers are disabled during library scans
func testAnalyzerScopeControl(t *testing.T) {
	// Create a minimal npm package.json
	packageJson := `{"name": "test", "version": "1.0.0", "dependencies": {}}`
	lockfilePath := filepath.Join(t.TempDir(), "package-lock.json")
	if err := os.WriteFile(lockfilePath, []byte(packageJson), 0644); err != nil {
		t.Fatalf("Failed to create test lockfile: %v", err)
	}

	libFilemap := map[string]scanner.LibFile{
		lockfilePath: {
			Contents: []byte(packageJson),
			Filemode: 0644,
		},
	}

	// Perform library analysis
	libraryScanners, err := scanner.AnalyzeLibraries(context.Background(), libFilemap, false)
	if err != nil {
		// This error is expected if the analyzer is not properly configured for library-only mode
		// The test verifies that the function attempts proper scope control
		t.Logf("AnalyzeLibraries encountered error (expected during regression): %v", err)
	}

	// Verify that the analyzer group is being used
	if len(libraryScanners) == 0 && err == nil {
		t.Logf("AnalyzeLibraries returned no scanners (may be expected for empty lockfile)")
	}
}

// testLibraryMapCompleteness checks that common ecosystem lockfiles are in the map
func testLibraryMapCompleteness(t *testing.T) {
	requiredMappings := map[string]string{
		ftypes.NpmPkgLock:      "node",
		ftypes.YarnLock:        "node",
		ftypes.GemfileLock:     "ruby",
		ftypes.CargoLock:       "rust",
		ftypes.ComposerLock:    "php",
		ftypes.PipRequirements: "python",
		ftypes.PipfileLock:     "python",
		ftypes.PoetryLock:      "python",
		ftypes.NuGetPkgsLock:   ".net",
		ftypes.NuGetPkgsConfig: ".net",
		ftypes.GoMod:           "gomod",
		ftypes.MavenPom:        "java",
	}

	missingEcosystems := []string{}
	for filename, expectedType := range requiredMappings {
		if actualType, exists := models.LibraryMap[filename]; !exists {
			missingEcosystems = append(missingEcosystems, filename)
		} else if actualType != expectedType {
			t.Errorf("LibraryMap[%s] = %s, expected %s", filename, actualType, expectedType)
		}
	}

	if len(missingEcosystems) > 0 {
		t.Errorf("Missing ecosystems in LibraryMap: %v. Projects using these package managers will have zero vulnerability findings.", missingEcosystems)
	}
}

